#!/bin/bash # pre-bash-gate.sh — PreToolUse hook (Bash) # Prevents agents from bypassing Write/Edit hooks via shell file-writing commands. # Detects common file-write patterns and applies the same enforcement as Write/Edit gates. # Exit 0 = allowed, Exit 2 = blocked # # WHY THIS EXISTS: Agents discovered they can bypass all Write/Edit hooks by using # python3/echo/tee/sed-i via the Bash tool. This hook closes that gap.  INPUT=$(cat) export HARNESS_SESSION_ID="$(printf '%s' "$INPUT" | jq -r '.session_id // ""' 2>/dev/null | tr -d '')"  # per-session must-do fan-out (mustdo_file_for_dir) COMMAND=$(printf '%s' "$INPUT" | jq -r '.tool_input.command // ""' 2>/dev/null)  # If no harness state, allow everything STATE_DIR="${HARNESS_STATE_DIR:-.claude/state}"  source "$HOME/.claude/scripts/lib-helpers.sh" 2>/dev/null  # --- HARNESS KILL-SWITCH (Sprint 33/35): resolved by project root (cwd-aware) --- if harness_disabled_resolved "$(pwd -W 2>/dev/null || pwd)" "" 2>/dev/null || [ -f "${STATE_DIR}/harness-disabled.flag" ]; then   exit 0 fi  # Heartbeat on EVERY Bash command so a busy (Bash-heavy) agent never goes stale and gets reaped mid-work. [ -n "${HARNESS_SESSION_ID:-}" ] && type watcher_touch_session >/dev/null 2>&1 && watcher_touch_session "$HARNESS_SESSION_ID" 2>/dev/null  # HARD SESSION ISOLATION (Bash): a WRITE command may not target ANOTHER, still-LIVE session's must-do # property (its summary lane or owned must-do file), whatever the path (relative, absolute, /tmp). # Own is fine; a dead/reaped owner's property is reclaimable; fail-open when no session id. Gated on a # write indicator (redirect / tee / cp / mv / sed -i / dd / truncate / heredoc / python open) so pure # reads are not blocked. Runs before the .claude/state bootstrap exemption (summaries live there). if [ -n "${HARNESS_SESSION_ID:-}" ] && type mustdo_peer_write_blocked >/dev/null 2>&1 \    && printf '%s' "$COMMAND" | grep -qE '>| (tee|cp|mv|dd|truncate|install) |sed [^|]*-i|<<|python[^|]* open '; then   for _iso_tok in $(printf '%s' "$COMMAND" | grep -oiE 'must-do[A-Za-z0-9._-]*\.(md|txt)' 2>/dev/null | sort -u); do     _ISO_PEER=$(mustdo_peer_write_blocked "$_iso_tok" "$HARNESS_SESSION_ID")     if [ -n "$_ISO_PEER" ]; then       printf "[SESSION ISOLATION] BLOCKED: this Bash command writes %s, which belongs to a DIFFERENT active session — off-limits.

" "$_iso_tok" >&2       printf "Write only your OWN must-do file / summary lane. A peer's property is reclaimable only after it ends.
" >&2       exit 2     fi   done fi  if [ ! -f "${STATE_DIR}/current-phase.json" ]; then   exit 0 fi  # Multilane lane resolution (Sprint 31a): override flat STATE_DIR with the lane's (lane 1 = flat, # transparent for single instance). Skipped when HARNESS_STATE_DIR is an explicit test override. if [ -z "${HARNESS_STATE_DIR:-}" ] && type resolve_instance >/dev/null 2>&1; then   resolve_instance "$INPUT" "$(pwd -W 2>/dev/null || pwd)" "PreToolUse" >/dev/null 2>&1   STATE_DIR="${STATE_DIR:-
